-- ============================================================
-- uni_modulos_onboarding_stepone_seed.sql
-- Onboarding Step One — 16 módulos novos para a Universidade Moní
-- Distribuídos nas Casas 1, 2, 3, 5 e 7 (Onboarding Step One v3)
-- NÃO altera os módulos existentes (14 preservados).
-- Idempotente: UPDATE onde (casa, ordem) já existe, INSERT onde não existe.
-- Rodar no SQL Editor DEV (bgaadvfucnrkpimaszjv) → validar → só então PROD.
-- ============================================================

-- Helper temporário de upsert por (casa slug, ordem). pg_temp é auto-descartado ao fim da sessão.
create function pg_temp.upsert_uni_modulo(
  _casa_slug text,
  _ordem     int,
  _tipo      text,
  _titulo    text,
  _conteudo  jsonb
) returns void language plpgsql as $fn$
declare
  _casa_id uuid;
  _mod_id  uuid;
begin
  select id into _casa_id from public.uni_casas where slug = _casa_slug;
  if _casa_id is null then
    raise exception 'Casa % não encontrada', _casa_slug;
  end if;

  select id into _mod_id from public.uni_modulos where casa_id = _casa_id and ordem = _ordem;
  if _mod_id is null then
    insert into public.uni_modulos (casa_id, tipo, titulo, conteudo, ordem, obrigatorio)
    values (_casa_id, _tipo, _titulo, _conteudo, _ordem, true);
  else
    update public.uni_modulos
      set tipo = _tipo, titulo = _titulo, conteudo = _conteudo, obrigatorio = true
      where id = _mod_id;
  end if;
end;
$fn$;

