    {"id":"q4","texto":"Qual é a nomenclatura correta para salvar um arquivo no Drive?","opcoes":["BCA_CondominioPalmeiras","FINAL_BCA_Palmeiras_DEFINITIVO","20260710_BCA_CondominioPalmeiras_v2","BCA_Palmeiras_julho"],"correta":"20260710_BCA_CondominioPalmeiras_v2"},
    {"id":"q5","texto":"Na Fase 6 (Lotes Disponíveis), qual atributo representa uma desvantagem do lote?","opcoes":["Vista privilegiada","Perto de área verde","Perto de lixeira","Possui muro lateral"],"correta":"Perto de lixeira"},
    {"id":"q6","texto":"Qual é o SLA das fases Mapa de Competidores e Dados dos Condomínios?","opcoes":["1 dia útil","2 dias úteis","3 dias úteis","5 dias úteis"],"correta":"3 dias úteis"},
    {"id":"q7","texto":"Qual ferramenta você usa para registrar os dados das 6 abas de análise (Mapa de Competidores, Resultado, Lotes, Check de Demanda, Valor x Giro, Hipótese)?","opcoes":["Hub Fly — checklist do card","Planilha Step One (R0 Análises de Viabilidade)","BCA Geral Moní 2026","Configurador Moní"],"correta":"Planilha Step One (R0 Análises de Viabilidade)"}
  ]}'::jsonb
);

